45	void ULFPHireMarketWidget::RefreshUnitList()
46	{
47		UnitButtons.Empty();
48		ButtonToUnitIndexMap.Empty();
49	
50		if (Box_UnitList)
51		{
52			Box_UnitList->ClearChildren();
53		}
54	
55		if (!CachedGameInstance || !CachedGameInstance->UnitRegistry || !Box_UnitList)
56		{
57			return;
58		}
59	
60		for (int32 i = 0; i < CachedHireMarketDefinition.UnitList.Num(); ++i)
61		{
62			const FLFPHireMarketUnitEntry& Entry = CachedHireMarketDefinition.UnitList[i];
63			FLFPUnitRegistryEntry UnitDefinition;
64			if (!CachedGameInstance->UnitRegistry->FindEntry(Entry.UnitTypeID, UnitDefinition))
65			{
66				continue;
67			}
68	
69			const bool bPurchased = CachedGameInstance->HasPurchasedHireMarketUnit(CachedHireMarketID, Entry.UnitTypeID);
70	
71			UButton* UnitButton = NewObject<UButton>(this);
72			if (!UnitButton)
73			{
74				continue;
75			}
76	
77			UTextBlock* Label = NewObject<UTextBlock>(UnitButton);
78			if (Label)
79			{
80				FString Suffix;
81				if (bPurchased)
82				{
83					Suffix = TEXT(" [已购买]");
84				}
85				else if (!CachedGameInstance->CanAffordGold(Entry.Price))
86				{
87					Suffix = TEXT(" [金币不足]");
88				}
89	
90				Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *UnitDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
91				UnitButton->AddChild(Label);
92			}
93	
94			UnitButton->SetIsEnabled(!bPurchased);
95	
96			UVerticalBoxSlot* ItemSlot = Box_UnitList->AddChildToVerticalBox(UnitButton);
97			if (ItemSlot)
98			{
99				ItemSlot->SetPadding(FMargin(4.f));
100			}
101	
102			UnitButton->OnClicked.AddDynamic(this, &ULFPHireMarketWidget::OnUnitButtonClicked);
103			UnitButtons.Add(UnitButton);
104			ButtonToUnitIndexMap.Add(UnitButton, i);
105		}
106	}
