108	void ULFPHireMarketWidget::RefreshDetailPanel()
109	{
110		if (!CachedGameInstance || !CachedGameInstance->UnitRegistry)
111		{
112			return;
113		}
114	
115		if (!CachedHireMarketDefinition.UnitList.IsValidIndex(SelectedUnitIndex))
116		{
117			if (Text_SelectedName) Text_SelectedName->SetText(FText::FromString(TEXT("未选择单位")));
118			if (Text_SelectedDescription) Text_SelectedDescription->SetText(FText::GetEmpty());
119			if (Text_SelectedPrice) Text_SelectedPrice->SetText(FText::GetEmpty());
120			if (Text_Status) Text_Status->SetText(FText::GetEmpty());
121			if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
122			if (Image_SelectedUnit) Image_SelectedUnit->SetBrushFromTexture(nullptr);
123			return;
124		}
125	
126		const FLFPHireMarketUnitEntry& Entry = CachedHireMarketDefinition.UnitList[SelectedUnitIndex];
127		FLFPUnitRegistryEntry UnitDefinition;
128		if (!CachedGameInstance->UnitRegistry->FindEntry(Entry.UnitTypeID, UnitDefinition))
129		{
130			if (Text_Status) Text_Status->SetText(FText::FromString(TEXT("单位定义缺失")));
131			if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
132			return;
133		}
134	
135		const bool bPurchased = CachedGameInstance->HasPurchasedHireMarketUnit(CachedHireMarketID, Entry.UnitTypeID);
136	
137		if (Image_SelectedUnit)
138		{
139			Image_SelectedUnit->SetBrushFromTexture(UnitDefinition.Icon);
140		}
141		if (Text_SelectedName)
142		{
143			Text_SelectedName->SetText(UnitDefinition.DisplayName);
144		}
145		if (Text_SelectedDescription)
146		{
147			Text_SelectedDescription->SetText(FText::FromString(BuildUnitDescription(Entry.UnitTypeID)));
148		}
149		if (Text_SelectedPrice)
150		{
151			Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
152		}
153	
154		const bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
155		const bool bCanPurchase = !bPurchased && bCanAfford;
156		if (Button_Purchase)
157		{
158			Button_Purchase->SetIsEnabled(bCanPurchase);
159		}
160		if (Text_PurchaseButton)
161		{
162			if (bPurchased)
163			{
164				Text_PurchaseButton->SetText(FText::FromString(TEXT("已雇佣")));
165			}
166			else if (!bCanAfford)
167			{
168				Text_PurchaseButton->SetText(FText::FromString(TEXT("金币不足")));
169			}
170			else
171			{
172				Text_PurchaseButton->SetText(FText::FromString(TEXT("雇佣")));
173			}
174		}
175		if (Text_Status)
176		{
177			if (bPurchased)
178			{
179				Text_Status->SetText(FText::FromString(TEXT("该单位已雇佣，当前市场不能重复雇佣")));
180			}
181			else if (!bCanAfford)
182			{
183				Text_Status->SetText(FText::FromString(TEXT("金币不足")));
184			}
185			else if (CachedGameInstance->IsPartyFull() && CachedGameInstance->IsReserveFull())
186			{
187				Text_Status->SetText(FText::FromString(TEXT("队伍与备战营已满，购买后需要替换现有单位")));
188			}
189			else if (CachedGameInstance->IsPartyFull())
190			{
191				Text_Status->SetText(FText::FromString(TEXT("出战队伍已满，购买后会进入备战营")));
192			}
193			else
194			{
195				Text_Status->SetText(FText::FromString(TEXT("可雇佣")));
196			}
197		}
198	}
