200	FString ULFPHireMarketWidget::BuildUnitDescription(FName UnitTypeID) const
201	{
202		if (!CachedGameInstance || !CachedGameInstance->UnitRegistry)
203		{
204			return TEXT("");
205		}
206	
207		FLFPUnitRegistryEntry UnitDefinition;
208		if (!CachedGameInstance->UnitRegistry->FindEntry(UnitTypeID, UnitDefinition))
209		{
210			return TEXT("单位定义缺失");
211		}
212	
213		const FString RaceName = StaticEnum<ELFPUnitRace>()->GetDisplayNameTextByValue(static_cast<int64>(UnitDefinition.Race)).ToString();
214		return FString::Printf(
215			TEXT("阶级: T%d\n种族: %s\n攻击: %d\n生命: %d\n移动: %d\n速度: %d\n行动次数: %d\n攻击次数: %d\n物理格挡: %d\n法术防御: %d\n重量: %d"),
216			UnitDefinition.Tier,
217			*RaceName,
218			UnitDefinition.BaseStats.Attack,
219			UnitDefinition.BaseStats.MaxHealth,
220			UnitDefinition.BaseStats.MaxMovePoints,
221			UnitDefinition.BaseStats.Speed,
222			UnitDefinition.AdvancedStats.ActionCount,
223			UnitDefinition.AdvancedStats.AttackCount,
224			UnitDefinition.AdvancedStats.PhysicalBlock,
225			UnitDefinition.AdvancedStats.SpellDefense,
226			UnitDefinition.AdvancedStats.Weight
227		);
228	}
