230	void ULFPHireMarketWidget::OnUnitButtonClicked()
231	{
232		for (const auto& Pair : ButtonToUnitIndexMap)
233		{
234			if (Pair.Key && Pair.Key->IsHovered())
235			{
236				SelectedUnitIndex = Pair.Value;
237				RefreshDetailPanel();
238				return;
239			}
240		}
241	}
242	
243	void ULFPHireMarketWidget::OnPurchaseClicked()
244	{
245		if (!CachedGameInstance || !CachedHireMarketDefinition.UnitList.IsValidIndex(SelectedUnitIndex))
246		{
247			return;
248		}
249	
250		const FLFPHireMarketUnitEntry& Entry = CachedHireMarketDefinition.UnitList[SelectedUnitIndex];
251		FLFPUnitEntry NewUnit;
252		if (!CachedGameInstance->TryPurchaseHireMarketUnit(CachedHireMarketID, Entry.UnitTypeID, Entry.Price, NewUnit))
253		{
254			RefreshHireMarketUI();
255			return;
256		}
257	
258		if (CachedGameInstance->TryAddUnit(NewUnit))
259		{
260			RefreshHireMarketUI();
261			return;
262		}
263	
264		if (ReplacementWidgetClass)
265		{
266			ReplacementWidget = CreateWidget<ULFPUnitReplacementWidget>(GetOwningPlayer(), ReplacementWidgetClass);
267			if (ReplacementWidget)
268			{
269				ReplacementWidget->OnReplacementComplete.AddDynamic(this, &ULFPHireMarketWidget::OnReplacementComplete);
270				ReplacementWidget->AddToViewport(10);
271				ReplacementWidget->Setup(NewUnit, CachedGameInstance->PartyUnits, CachedGameInstance->ReserveUnits, CachedGameInstance->UnitRegistry);
272			}
273		}
274	}
