284	{
285		if (ReplacementWidget)
286		{
287			ReplacementWidget->OnReplacementComplete.RemoveDynamic(this, &ULFPHireMarketWidget::OnReplacementComplete);
288			ReplacementWidget->RemoveFromParent();
289			ReplacementWidget = nullptr;
290		}
291	
292		RefreshHireMarketUI();
293	}
