27	void ALFPWorldMapPlayerController::BeginPlay()
28	{
29		Super::BeginPlay();
30	
31		// 设置输入模式
32		FInputModeGameAndUI InputMode;
33		InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
34		InputMode.SetHideCursorDuringCapture(false);
35		SetInputMode(InputMode);
36		bShowMouseCursor = true;
37	
38		// 设置 Enhanced Input
39		if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
40		{
41			if (DefaultInputMapping)
42			{
43				Subsystem->AddMappingContext(DefaultInputMapping, 0);
44			}
45		}
46	
47		// 场景切换淡入效果
48		if (PlayerCameraManager)
49		{
50			ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
51			float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
52			PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
53		}
54	
55		// 首帧跳过相机平滑插值
56		bSnapCameraNextFrame = true;
57	}
58	
59	void ALFPWorldMapPlayerController::Tick(float DeltaTime)
60	{
61		Super::Tick(DeltaTime);
62	
63		if (bIsDragging)
64		{
65			DragTime += DeltaTime;
66		}
67	
68		// 更新相机位置和旋转
69		// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
70		FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
71	
72		// 相机旋转：俯视角
73		FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
74	
75		// 平滑插值并设置
76		FRotator CurrentRotation = GetControlRotation();
77		if (bSnapCameraNextFrame)
78		{
79			SetControlRotation(TargetRotation);
80		}
81		else
82		{
83			SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
84		}
85	
86		// 通过 Pawn 控制相机位置（如果有 Pawn）
87		if (APawn* ControlledPawn = GetPawn())
88		{
89			if (bSnapCameraNextFrame)
90			{
91				// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
92				ControlledPawn->SetActorLocation(TargetLocation);
93				bSnapCameraNextFrame = false;
94			}
95			else
96			{
97				FVector CurrentLocation = ControlledPawn->GetActorLocation();
