424	void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
425	{
426		if (!Node) return;
427	
428		UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
429	
430		switch (Node->NodeType)
431		{
432		case ELFPWorldNodeType::WNT_Battle:
433		case ELFPWorldNodeType::WNT_Boss:
434			EnterBattle(Node);
435			break;
436	
437		case ELFPWorldNodeType::WNT_Event:
438			// TODO: 触发事件系统
439			UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
440			break;
441	
442		case ELFPWorldNodeType::WNT_Shop:
443			OpenShop(Node, false);
444			break;
445	
446		case ELFPWorldNodeType::WNT_HireMarket:
447			OpenHireMarket(Node, false);
448			break;
449	
450		case ELFPWorldNodeType::WNT_Town:
451			OpenTown(Node);
452			break;
453	
454		case ELFPWorldNodeType::WNT_QuestNPC:
455			// TODO: 触发任务对话
456			UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
457			break;
458	
459		case ELFPWorldNodeType::WNT_SkillNode:
460			// TODO: 打开技能树 UI
461			UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
462			break;
463	
464		case ELFPWorldNodeType::WNT_EvolutionTower:
465			OpenEvolutionTower();
466			break;
467	
468		default:
469			break;
470		}
471	}
