818		if (!Manager || !TeleportWidgetClass) return;
819	
820		ULFPWorldMapPlayerState* PS = Manager->GetPlayerState();
821		if (!PS) return;
822	
823		// 获取可传送目的地
824		TArray<ALFPWorldMapNode*> Destinations = Manager->GetTeleportDestinations(PS->CurrentNodeID);
825	
826		// 创建或显示 TeleportWidget
827		if (!TeleportWidget)
828		{
829			TeleportWidget = CreateWidget<ULFPTeleportWidget>(this, TeleportWidgetClass);
830			if (TeleportWidget)
831			{
832				TeleportWidget->OnTeleportTargetSelected.AddDynamic(this, &ALFPWorldMapPlayerController::OnTeleportTargetSelected);
833				TeleportWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnTeleportWidgetClosed);
834				TeleportWidget->AddToViewport();
835			}
836		}
837		else
838		{
839			TeleportWidget->SetVisibility(ESlateVisibility::Visible);
840			TeleportWidget->AddToViewport();
841		}
842	
843		if (TeleportWidget)
844		{
845			TeleportWidget->Setup(Destinations);
