22	// ============== 节点管理 ==============
23	
24	ALFPWorldMapNode* ALFPWorldMapManager::SpawnNode(int32 NodeID, FVector2D Position, ELFPWorldNodeType NodeType)
25	{
26		// 检查 ID 冲突
27		if (NodeMap.Contains(NodeID))
28		{
29			UE_LOG(LogTemp, Warning, TEXT("SpawnNode: 节点 ID %d 已存在"), NodeID);
30			return NodeMap[NodeID];
31		}
32	
33		if (!NodeActorClass)
34		{
35			UE_LOG(LogTemp, Error, TEXT("SpawnNode: NodeActorClass 未配置"));
36			return nullptr;
37		}
38	
39		FVector SpawnLocation(Position.X, Position.Y, 0.f);
40		FActorSpawnParameters SpawnParams;
41		SpawnParams.Owner = this;
42	
43		ALFPWorldMapNode* NewNode = GetWorld()->SpawnActor<ALFPWorldMapNode>(
44			NodeActorClass, SpawnLocation, FRotator::ZeroRotator, SpawnParams);
45	
46		if (!NewNode) return nullptr;
47	
48		NewNode->NodeID = NodeID;
49		NewNode->NodeType = NodeType;
50		NewNode->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
51	
52		// 应用视觉数据
53		if (ULFPWorldNodeDataAsset* VisualData = GetNodeVisualForType(NodeType))
54		{
55			NewNode->SetNodeVisualData(VisualData);
56		}
57	
58		NodeMap.Add(NodeID, NewNode);
59	
60		// 确保邻接表有条目
61		if (!AdjacencyList.Contains(NodeID))
62		{
63			AdjacencyList.Add(NodeID, TSet<int32>());
64		}
65	
66		// 更新 ID 计数器
67		if (NodeID >= NextNodeID)
68		{
69			NextNodeID = NodeID + 1;
70		}
71	
72		return NewNode;
73	}
74	
75	bool ALFPWorldMapManager::RemoveNode(int32 NodeID)
76	{
77		ALFPWorldMapNode** Found = NodeMap.Find(NodeID);
78		if (!Found) return false;
79	
80		// 先移除所有关联边
81		if (TArray<FIntPoint>* EdgeKeys = NodeEdgeIndex.Find(NodeID))
82		{
83			// 复制一份，因为 RemoveEdge 会修改 NodeEdgeIndex
84			TArray<FIntPoint> KeysCopy = *EdgeKeys;
85			for (const FIntPoint& Key : KeysCopy)
86			{
87				if (ALFPWorldMapEdge** EdgeFound = EdgeMap.Find(Key))
88				{
89					int32 OtherID = (Key.X == NodeID) ? Key.Y : Key.X;
90					RemoveEdge(NodeID, OtherID);
91				}
92			}
93		}
94	
95		// 销毁 Actor
96		if (*Found)
97		{
98			(*Found)->Destroy();
99		}
100	
101		NodeMap.Remove(NodeID);
102		AdjacencyList.Remove(NodeID);
103		NodeEdgeIndex.Remove(NodeID);
104	
105		return true;
106	}
