343	bool ALFPWorldMapManager::SaveNodesToCSV(const FString& FilePath)
344	{
345		// CSV 头部（UE DataTable 格式）
346		FString CSVContent = TEXT("---,NodeID,PosX,PosY,NodeType,BattleMapName,StarRating,bCanEscape,BaseGoldReward,BaseFoodReward,EventID,TownBuildingList,ShopID,HireMarketID,PrerequisiteNodeIDs\n");
347	
348		for (const auto& Pair : NodeMap)
349		{
350			ALFPWorldMapNode* Node = Pair.Value;
351			if (!Node) continue;
352	
353			FLFPWorldNodeRow Row = Node->ExportToRowData();
354			FString RowName = FString::FromInt(Row.NodeID);
355	
356			// 节点类型枚举名
357			FString NodeTypeStr = UEnum::GetValueAsString(Row.NodeType);
358			NodeTypeStr = NodeTypeStr.RightChop(NodeTypeStr.Find(TEXT("::")) + 2);
359	
360			CSVContent += FString::Printf(TEXT("%s,%d,%f,%f,%s,%s,%d,%s,%d,%d,%s,%s,%s,%s,%s\n"),
361				*RowName,
362				Row.NodeID,
363				Row.PosX,
364				Row.PosY,
365				*NodeTypeStr,
366				*Row.BattleMapName,
367				Row.StarRating,
368				Row.bCanEscape ? TEXT("True") : TEXT("False"),
369				Row.BaseGoldReward,
370				Row.BaseFoodReward,
371				*Row.EventID,
372				*Row.TownBuildingList,
373				*Row.ShopID.ToString(),
374				*Row.HireMarketID.ToString(),
375				*Row.PrerequisiteNodeIDs);
376		}
377	
378		// 确保目录存在
379		FString Directory = FPaths::GetPath(FilePath);
380		if (!FPaths::DirectoryExists(Directory))
381		{
382			IFileManager::Get().MakeDirectory(*Directory, true);
383		}
384	
385		bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *FilePath,
386			FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
387	
388		if (bSuccess)
389		{
390			UE_LOG(LogTemp, Log, TEXT("SaveNodesToCSV: 保存 %d 个节点到 %s"), NodeMap.Num(), *FilePath);
391		}
392		else
393		{
394			UE_LOG(LogTemp, Error, TEXT("SaveNodesToCSV: 保存失败 %s"), *FilePath);
395		}
396		return bSuccess;
397	}
