399	bool ALFPWorldMapManager::SaveEdgesToCSV(const FString& FilePath)
400	{
401		FString CSVContent = TEXT("---,FromNodeID,ToNodeID,TravelTurnCost\n");
402	
403		for (const auto& Pair : EdgeMap)
404		{
405			ALFPWorldMapEdge* Edge = Pair.Value;
406			if (!Edge) continue;
407	
408			FLFPWorldEdgeRow Row = Edge->ExportToRowData();
409			FString RowName = FString::Printf(TEXT("%d_%d"), Row.FromNodeID, Row.ToNodeID);
410	
411			CSVContent += FString::Printf(TEXT("%s,%d,%d,%d\n"),
412				*RowName, Row.FromNodeID, Row.ToNodeID, Row.TravelTurnCost);
413		}
414	
415		FString Directory = FPaths::GetPath(FilePath);
416		if (!FPaths::DirectoryExists(Directory))
417		{
418			IFileManager::Get().MakeDirectory(*Directory, true);
419		}
420	
421		bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *FilePath,
422			FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
423	
424		if (bSuccess)
425		{
426			UE_LOG(LogTemp, Log, TEXT("SaveEdgesToCSV: 保存 %d 条边到 %s"), EdgeMap.Num(), *FilePath);
427		}
428		else
429		{
430			UE_LOG(LogTemp, Error, TEXT("SaveEdgesToCSV: 保存失败 %s"), *FilePath);
431		}
432		return bSuccess;
433	}
