80	void ALFPWorldMapGameMode::HandleBattleResult(const FLFPBattleResult& Result)
81	{
82		if (!WorldMapManager) return;
83	
84		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
85	
86		UE_LOG(LogTemp, Log, TEXT("处理战斗结果: 节点 %d, 胜利=%s, 逃跑=%s"),
87			Result.SourceNodeID,
88			Result.bVictory ? TEXT("是") : TEXT("否"),
89			Result.bEscaped ? TEXT("是") : TEXT("否"));
90	
91		if (Result.bVictory)
92		{
93			// 胜利：节点标记为已触发（如果尚未标记）
94			ALFPWorldMapNode* Node = WorldMapManager->GetNode(Result.SourceNodeID);
95			if (Node && !Node->bHasBeenTriggered)
96			{
97				Node->bHasBeenTriggered = true;
98				Node->UpdateVisualState();
99			}
100	
101			// 发放奖励到 GameInstance
102			if (GI)
103			{
104				GI->AddGold(Result.GoldReward);
105				GI->AddFood(Result.FoodReward);
106				UE_LOG(LogTemp, Log, TEXT("战斗奖励: 金币 +%d, 食物 +%d"), Result.GoldReward, Result.FoodReward);
107			}
108	
109			// 处理捕获的单位
110			if (Result.CapturedUnits.Num() > 0)
111			{
112				ProcessCapturedUnits(Result.CapturedUnits);
113			}
114		}
115		else if (Result.bEscaped)
116		{
117			// 逃跑：不标记为已触发，可再次进入，不发放奖励
118			UE_LOG(LogTemp, Log, TEXT("逃跑：节点 %d 未标记为已触发"), Result.SourceNodeID);
119		}
120		else
121		{
122			// 失败：不标记节点，可重试，不发放奖励
123			UE_LOG(LogTemp, Warning, TEXT("战斗失败：节点 %d，可重试"), Result.SourceNodeID);
124		}
125	}
