549	// ============== 迷雾系统 ==============
550	
551	TSet<int32> ALFPWorldMapManager::GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const
552	{
553		TSet<int32> Result;
554	
555		if (!AdjacencyList.Contains(StartNodeID)) return Result;
556	
557		// BFS
558		TQueue<TPair<int32, int32>> Queue; // <NodeID, Distance>
559		TSet<int32> Visited;
560	
561		Queue.Enqueue(TPair<int32, int32>(StartNodeID, 0));
562		Visited.Add(StartNodeID);
563	
564		while (!Queue.IsEmpty())
565		{
566			TPair<int32, int32> Current;
567			Queue.Dequeue(Current);
568	
569			int32 CurrentID = Current.Key;
570			int32 CurrentDist = Current.Value;
571	
572			Result.Add(CurrentID);
573	
574			if (CurrentDist >= MaxDistance) continue;
575	
576			if (const TSet<int32>* Neighbors = AdjacencyList.Find(CurrentID))
577			{
578				for (int32 NeighborID : *Neighbors)
579				{
580					if (!Visited.Contains(NeighborID))
581					{
582						Visited.Add(NeighborID);
583						Queue.Enqueue(TPair<int32, int32>(NeighborID, CurrentDist + 1));
584					}
585				}
586			}
587		}
588	
589		return Result;
590	}
