592	void ALFPWorldMapManager::UpdateFog()
593	{
594		if (!PlayerState) return;
595	
596		// 获取视野范围内的节点
597		TSet<int32> VisibleNodes = GetNodesWithinGraphDistance(PlayerState->CurrentNodeID, FogVisionRange);
598	
599		// 添加到永久揭露集合
600		for (int32 NodeID : VisibleNodes)
601		{
602			PlayerState->RevealedNodeIDs.Add(NodeID);
603		}
604	
605		// 更新所有节点的视觉状态
606		for (auto& Pair : NodeMap)
607		{
608			if (!Pair.Value) continue;
609	
610			Pair.Value->bIsRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key);
611			Pair.Value->UpdateVisualState();
612		}
613	
614		// 更新边的可见性（两端都揭露才可见）
615		for (auto& Pair : EdgeMap)
616		{
617			if (!Pair.Value) continue;
618	
619			bool bBothRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key.X)
620				&& PlayerState->RevealedNodeIDs.Contains(Pair.Key.Y);
621			Pair.Value->SetActorHiddenInGame(!bBothRevealed);
622		}
623	}
