627	void ALFPWorldMapManager::InitializePlayer(int32 StartNodeID)
628	{
629		if (!PlayerState)
630		{
631			PlayerState = NewObject<ULFPWorldMapPlayerState>(this);
632		}
633	
634		PlayerState->Initialize(StartNodeID);
635	
636		// 生成或移动玩家棋子到起始节点
637		ALFPWorldMapNode* StartNode = GetNode(StartNodeID);
638		FVector StartLocation = StartNode ? StartNode->GetActorLocation() + FVector(0, 0, 1) : FVector::ZeroVector;
639	
640		if (!PlayerPawn && PawnActorClass)
641		{
642			FActorSpawnParameters SpawnParams;
643			SpawnParams.Owner = this;
644			PlayerPawn = GetWorld()->SpawnActor<ALFPWorldMapPawn>(
645				PawnActorClass, StartLocation, FRotator::ZeroRotator, SpawnParams);
646	
647			if (PlayerPawn)
648			{
649				PlayerPawn->OnMoveComplete.AddDynamic(this, &ALFPWorldMapManager::OnPawnMoveComplete);
650			}
651		}
652		else if (PlayerPawn)
653		{
654			PlayerPawn->SetLocationImmediate(StartLocation);
655		}
656	
657		// 初始迷雾更新
658		UpdateFog();
659	
660		UE_LOG(LogTemp, Log, TEXT("玩家初始化在节点 %d"), StartNodeID);
661	}
