663	bool ALFPWorldMapManager::MovePlayer(int32 TargetNodeID)
664	{
665		if (!PlayerState) return false;
666	
667		// 棋子移动中不允许再次移动
668		if (PlayerPawn && PlayerPawn->IsMoving()) return false;
669	
670		bool bMoved = PlayerState->MoveToNode(TargetNodeID, this);
671	
672		if (bMoved)
673		{
674			ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
675			if (!TargetNode) return true;
676	
677			// 如果有棋子，启动移动动画，延迟迷雾更新和事件触发
678			if (PlayerPawn)
679			{
680				PendingMoveTargetNodeID = TargetNodeID;
681				FVector TargetLocation = TargetNode->GetActorLocation() + FVector(0, 0, 1);
682				PlayerPawn->MoveToLocation(TargetLocation);
683			}
684			else
685			{
686				// 没有棋子，直接执行后续逻辑
687				HandlePostMove(TargetNodeID);
688			}
689		}
690	
691		return bMoved;
692	}
