704	void ALFPWorldMapManager::HandlePostMove(int32 TargetNodeID)
705	{
706		// 更新迷雾
707		UpdateFog();
708	
709		// 触发节点事件（首次进入未触发的节点）
710		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
711		if (TargetNode && !TargetNode->bHasBeenTriggered)
712		{
713			switch (TargetNode->NodeType)
714			{
715			case ELFPWorldNodeType::WNT_Battle:
716			case ELFPWorldNodeType::WNT_Event:
717			case ELFPWorldNodeType::WNT_Boss:
718				TargetNode->bHasBeenTriggered = true;
719				TargetNode->UpdateVisualState();
720				break;
721			default:
722				break;
723			}
724		}
725	
726		// 回合压力检查
727		if (PlayerState && PlayerState->IsPastPressureThreshold())
728		{
729			UE_LOG(LogTemp, Warning, TEXT("回合压力: 已超过 %d 回合阈值！当前 %d 回合"),
730				PlayerState->TurnPressureThreshold, PlayerState->CurrentTurn);
731		}
732	}
