739	bool ALFPWorldMapManager::TeleportPlayerToNode(int32 TargetNodeID)
740	{
741		if (!PlayerState) return false;
742	
743		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
744		if (!TargetNode) return false;
745	
746		// 直接更新玩家状态（不校验相邻、不消耗回合）
747		PlayerState->SetCurrentNodeDirectly(TargetNodeID, TargetNode);
748	
749		// 立即移动棋子（不走动画）
750		if (PlayerPawn)
751		{
752			FVector TargetLocation = TargetNode->GetActorLocation() + FVector(0, 0, 1);
753			PlayerPawn->SetLocationImmediate(TargetLocation);
754		}
755	
756		// 更新迷雾
757		UpdateFog();
758	
759		UE_LOG(LogTemp, Log, TEXT("传送: 玩家传送到节点 %d"), TargetNodeID);
760		return true;
761	}
