763	TArray<ALFPWorldMapNode*> ALFPWorldMapManager::GetTeleportDestinations(int32 ExcludeNodeID) const
764	{
765		TArray<ALFPWorldMapNode*> Result;
766	
767		for (const auto& Pair : NodeMap)
768		{
769			ALFPWorldMapNode* Node = Pair.Value;
770			if (!Node || Node->NodeID == ExcludeNodeID) continue;
771	
772			// 只选城镇节点且建筑列表包含 Teleport
773			if (Node->NodeType == ELFPWorldNodeType::WNT_Town && Node->TownBuildingList.Contains(TEXT("Teleport")))
774			{
775				Result.Add(Node);
776			}
777		}
778	
779		return Result;
780	}
