386	// ============== 单位升阶 ==============
387	
388	TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
389	{
390		// 统计每个 TypeID 的出现次数
391		TMap<FName, int32> CountMap;
392	
393		for (const FLFPUnitEntry& Unit : PartyUnits)
394		{
395			if (Unit.IsValid())
396			{
397				CountMap.FindOrAdd(Unit.TypeID, 0)++;
398			}
399		}
400		for (const FLFPUnitEntry& Unit : ReserveUnits)
401		{
402			if (Unit.IsValid())
403			{
404				CountMap.FindOrAdd(Unit.TypeID, 0)++;
405			}
406		}
407	
408		// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
409		TArray<FLFPUnitEntry> Result;
410		for (const auto& Pair : CountMap)
411		{
412			if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
413			{
414				FLFPUnitEntry Entry;
415				Entry.TypeID = Pair.Key;
416				Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
417				Result.Add(Entry);
418			}
419		}
420	
421		return Result;
422	}
423	
424	bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
425		bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
426	{
427		TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
428		TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
429	
430		if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
431		{
432			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
433			return false;
434		}
435	
436		const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
437		const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
438	
439		// 验证两个源单位 TypeID 相同
440		if (UnitA.TypeID != UnitB.TypeID)
441		{
442			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
443				*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
444			return false;
445		}
446	
447		// 验证 TargetTypeID 在进化目标列表中
448		if (!UnitRegistry)
449		{
450			UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
451			return false;
452		}
453	
454		TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
455		if (!Targets.Contains(TargetTypeID))
456		{
457			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
458				*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
459			return false;
460		}
461	
462		// 创建进化后的新单位
463		FLFPUnitEntry NewUnit;
464		NewUnit.TypeID = TargetTypeID;
465		NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
466	
467		// 移除两个源单位（同一数组时先移除大索引避免偏移）
468		if (bSourceAIsParty == bSourceBIsParty)
469		{
470			int32 First = FMath::Max(SourceAIndex, SourceBIndex);
471			int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
472			ArrayA.RemoveAt(First);
473			ArrayA.RemoveAt(Second);
474		}
475		else
476		{
477			ArrayA.RemoveAt(SourceAIndex);
478			ArrayB.RemoveAt(SourceBIndex);
479		}
480	
481		TryAddUnit(NewUnit);
482	
483		UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
484			*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
485	
486		return true;
487	}
